(573, 28, 'Ciclo II', 'Profundizar en el análisis matemático, la física aplicada y el dibujo técnico, sentando las bases para el diseño y la comprensión de problemas ingenieriles, con enfoque en geometría y representación gráfica.', '[\"REALIDAD NACIONAL Y DERECHOS HUMANOS\",\"AN\\u00c1LISIS MATEM\\u00c1TICO I\",\"F\\u00cdSICA II\",\"GEOMETR\\u00cdA DESCRIPTIVA\",\"DIBUJO EN INGENIER\\u00cdA I\"]', '2026-06-19 20:39:01', '2026-06-19 20:39:01'),
(574, 28, 'Ciclo III', 'Desarrollar competencias en estadística, pensamiento crítico y análisis matemático avanzado, junto con principios de estática y geología, para aplicar metodologías científicas en la solución de problemas de ingeniería civil.', '[\"ESTAD\\u00cdSTICA Y PROBABILIDADES\",\"DESARROLLO DEL PENSAMIENTO CR\\u00cdTICO\",\"AN\\u00c1LISIS MATEM\\u00c1TICO II\",\"EST\\u00c1TICA\",\"GEOLOG\\u00cdA\",\"DIBUJO EN INGENIER\\u00cdA II\"]', '2026-06-19 20:39:01', '2026-06-19 20:39:01'),
(575, 28, 'Ciclo IV', 'Fortalecer habilidades en investigación científica, análisis estructural y dinámica, junto con el estudio de ecología y topografía, integrando conocimientos teóricos y prácticos para el diseño y evaluación de proyectos.', '[\"METODOLOG\\u00cdA DE LA INVESTIGACI\\u00d3N CIENT\\u00cdFICA\",\"AN\\u00c1LISIS MATEM\\u00c1TICO III\",\"ECOLOG\\u00cdA E IMPACTO AMBIENTAL\",\"TOPOGRAF\\u00cdA I\",\"DIN\\u00c1MICA\",\"RESISTENCIA DE MATERIALES\"]', '2026-06-19 20:39:01', '2026-06-19 20:39:01'),
(576, 28, 'Ciclo V', 'Aplicar conocimientos en mecánica de fluidos, resistencia de materiales y tecnología del concreto, enfatizando en el análisis estructural y la topografía avanzada para el desarrollo de infraestructuras sostenibles.', '[\"INGL\\u00c9S APLICADO A INGENIERIA\",\"TOPOGRAF\\u00cdA II\",\"MEC\\u00c1NICA DE FLUIDOS\",\"AN\\u00c1LISIS ESTRUCTURAL I\",\"MEC\\u00c1NICA DE SUELOS\",\"TECNOLOG\\u00cdA DEL CONCRETO\"]', '2026-06-19 20:39:01', '2026-06-19 20:39:01'),
(577, 28, 'Ciclo VI', 'Profundizar en ética profesional, modelamiento digital (BIM), concreto armado y tecnología de la construcción, preparando al estudiante para gestionar proyectos con innovación y responsabilidad social.', '[\"\\u00c9TICA Y RESPONSABILIDAD PROFESIONAL\",\"INSTALACIONES DE EDIFICACIONES\",\"MODELAMIENTO DIGITAL BIM I\",\"CONCRETO ARMADO\",\"TECNOLOG\\u00cdA DE LA CONSTRUCCI\\u00d3N\",\"AN\\u00c1LISIS ESTRUCTURAL II\"]', '2026-06-19 20:39:01', '2026-06-19 20:39:01'),
(578, 28, 'Ciclo VII', 'Desarrollar habilidades en gerencia de proyectos, hidráulica, prevención de riesgos y modelamiento avanzado (BIM II), enfocándose en la planificación y ejecución de obras civiles con estándares de calidad y seguridad.', '[\"INGENIER\\u00cdA DE COSTOS Y PLANEAMIENTO\",\"HIDR\\u00c1ULICA E HIDROLOG\\u00cdA\",\"GERENCIA DE PROYECTOS DE CONSTRUCCI\\u00d3N\",\"PREVENCI\\u00d3N DE RIESGOS LABORALES\",\"MODELAMIENTO DIGITAL BIM II\",\"ALBA\\u00d1ILER\\u00cdA ESTRUCTURAL\"]', '2026-06-19 20:39:01', '2026-06-19 20:39:01'),
(579, 28, 'Ciclo VIII', 'Especializarse en abastecimiento de agua, pavimentos, geotecnia y planeamiento urbano, integrando tecnologías innovadoras para el diseño y construcción de infraestructuras resilientes y sostenibles.', '[\"ABASTECIMIENTO DE AGUA Y SANEAMIENTO\",\"PLANEAMIENTO URBANO Y LICENCIAS DE CONSTRUCCI\\u00d3N\",\"PAVIMENTOS\",\"INNOVACI\\u00d3N TECNOL\\u00d3GICA EN LA CONSTRUCCI\\u00d3N\",\"ELECTIVO I\",\"GEOTECNIA, MUROS Y CIMENTACIONES\"]', '2026-06-19 20:39:01', '2026-06-19 20:39:01'),
(580, 28, 'Ciclo IX', 'Realizar actividades de proyección social, investigación (seminario de tesis) y práctica preprofesional, aplicando conocimientos en proyectos de inversión pública y recursos hidráulicos para soluciones ingenieriles reales.', '[\"ACTIVIDADES DE PROYECCI\\u00d3N SOCIAL Y VIDA UNIVERSITARIA\",\"PROYECTOS DE INGENIER\\u00cdA E INVERSI\\u00d3N P\\u00daBLICA\",\"INGENIER\\u00cdA DE RECURSOS HIDR\\u00c1ULICOS\",\"SEMINARIO DE TESIS\",\"PR\\u00c1CTICA PREPROFESIONAL I\",\"ELECTIVO II\"]', '2026-06-19 20:39:01', '2026-06-19 20:39:01'),
(581, 28, 'Ciclo X', 'Culminar con el trabajo de investigación, práctica preprofesional avanzada y seminarios de obras públicas, consolidando competencias para el ejercicio profesional en ingeniería civil con enfoque en sostenibilidad y normativa legal.', '[\"SEMINARIO DE OBRAS P\\u00daBLICAS\",\"INGENIER\\u00cdA SISMORRESISTENTE\",\"TRABAJO DE INVESTIGACI\\u00d3N\",\"PR\\u00c1CTICA PREPROFESIONAL II\",\"ELECTIVO III\"]', '2026-06-19 20:39:01', '2026-06-19 20:39:01'),
(582, 43, 'Ciclo I', 'Desarrollar fundamentos en inteligencia artificial, marketing estratégico, transformación digital, ética, liderazgo, comportamiento organizacional e investigación de mercados, estableciendo la base conceptual y técnica para aplicar estrategias digitales innovadoras en contextos empresariales.', '[\"FUNDAMENTOS DE INTELIGENCIA ARTIFICIAL\",\"MARKETING ESTRAT\\u00c9GICO Y TRANSFORMACI\\u00d3N DIGITAL\",\"\\u00c9TICA Y RESPONSABILIDAD SOCIAL\",\"COMPORTAMIENTO ORGANIZACIONAL Y LIDERAZGO\",\"INVESTIGACI\\u00d3N DE MERCADOS\"]', '2026-06-19 20:42:40', '2026-06-19 20:42:40'),
(583, 43, 'Ciclo II', 'Fortalecer competencias en análisis de métricas, SEO, SEM, publicidad programática, branding digital, herramientas de IA para marketing, experiencia del cliente y metodología científica, integrando capacidades tecnológicas y estratégicas para la gestión comercial.', '[\"AN\\u00c1LISIS DE M\\u00c9TRICAS Y KPI\\u2019S EN MARKETING\",\"HERRAMIENTAS DE MARKETING BASADAS EN INTELIGENCIA ARTIFICIAL\",\"ESTRATEGIAS DE PUBLICIDAD Y BRANDING DIGITAL\",\"GESTI\\u00d3N DE LA RELACI\\u00d3N CON LOS CLIENTES & USER EXPERIENCE\",\"METODOLOG\\u00cdA DE LA INVESTIGACI\\u00d3N CIENT\\u00cdFICA\",\"ANAL\\u00cdTICA WEB, SEO, SEM Y PUBLICIDAD PROGRAM\\u00c1TICA\"]', '2026-06-19 20:42:40', '2026-06-19 20:42:40');
INSERT INTO `carrera_malla_curricular` (`id`, `carrera_id`, `ciclo`, `descripcion`, `cursos`, `created_at`, `updated_at`) VALUES
(584, 43, 'Ciclo III', 'Aplicar conocimientos avanzados en Big Data, machine learning, automatización de marketing, growth hacking, persuasión y ventas, culminando con un trabajo de investigación aplicada que articule innovación digital, inteligencia artificial y gestión comercial estratégica.', '[\"BIG DATA Y LA INTELIGENCIA ARTIFICIAL EN LA GESTI\\u00d3N COMERCIAL\",\"INTELIGENCIA ARTIFICIAL Y MACHINE LEARNING PARA LA PERSONALIZACI\\u00d3N\",\"MARKETING AUTOMATION Y GROWTH HACKING\",\"TRABAJO DE INVESTIGACI\\u00d3N APLICADA\",\"CIERRE DE VENTAS, T\\u00c9CNICAS DE PERSUASI\\u00d3N Y PSICOLOG\\u00cdA DEL CLIENTE\"]', '2026-06-19 20:42:40', '2026-06-19 20:42:40'),
(585, 45, 'Ciclo I', 'Desarrollar conocimientos en finanzas, marketing estratégico, transformación digital, ética empresarial, liderazgo organizacional e investigación de mercados, formando una base sólida para la toma de decisiones comerciales y el desarrollo de estrategias orientadas al cliente y la sostenibilidad.', '[\"CONTABILIDAD GERENCIAL Y FINANZAS\",\"MARKETING ESTRAT\\u00c9GICO Y TRANSFORMACI\\u00d3N DIGITAL\",\"\\u00c9TICA Y RESPONSABILIDAD SOCIAL\",\"COMPORTAMIENTO ORGANIZACIONAL Y LIDERAZGO\",\"INVESTIGACI\\u00d3N DE MERCADOS\"]', '2026-06-19 20:47:34', '2026-06-19 20:47:34'),
(586, 45, 'Ciclo II', 'Fortalecer habilidades en ventas, branding, análisis de métricas, gestión de cuentas clave, experiencia del cliente y metodología científica, integrando enfoques modernos de marketing con liderazgo comercial para impulsar la competitividad empresarial.', '[\"GESTI\\u00d3N DE VENTAS Y LIDERAZGO COMERCIAL\",\"ESTRATEGIAS DE PUBLICIDAD Y BRANDING DIGITAL\",\"AN\\u00c1LISIS DE M\\u00c9TRICAS Y KPI\\u2019S EN MARKETING\",\"NEGOCIACI\\u00d3N Y GESTI\\u00d3N DE CUENTAS CLAVE (KEY ACCOUNT MANAGEMENT)\",\"GESTI\\u00d3N DE LA RELACI\\u00d3N CON LOS CLIENTES Y USER EXPERIENCE\",\"METODOLOG\\u00cdA DE LA INVESTIGACI\\u00d3N CIENT\\u00cdFICA\"]', '2026-06-19 20:47:34', '2026-06-19 20:47:34'),
(587, 45, 'Ciclo III', 'Aplicar técnicas avanzadas en pricing, canales de distribución, automatización de marketing, persuasión y psicología del consumidor, culminando con una investigación aplicada que articule teoría y práctica en la gestión estratégica comercial y digital.', '[\"GESTI\\u00d3N DE PRECIOS\",\"GESTI\\u00d3N DE CANALES DE DISTRIBUCI\\u00d3N\",\"MARKETING AUTOMATION Y GROWTH HACKING\",\"TRABAJO DE INVESTIGACI\\u00d3N APLICADA\",\"CIERRE DE VENTAS, T\\u00c9CNICAS DE PERSUASI\\u00d3N Y PSICOLOG\\u00cdA DEL CLIENTE\"]', '2026-06-19 20:47:34', '2026-06-19 20:47:34'),
(588, 49, 'Ciclo I', 'Desarrollar conocimientos fundamentales sobre corrupción, integridad pública, marcos normativos, lavado de activos y el rol de la UIF, formando una base integral jurídica, ética y sociopolítica para enfrentar los delitos contra la administración pública y el sistema financiero.', '[\"BASES SOCIOL\\u00d3GICAS Y ANTROPOL\\u00d3GICAS DEL FEN\\u00d3MENO DE LA CORRUPCI\\u00d3N\",\"DISE\\u00d1O E IMPLEMENTACI\\u00d3N DE POL\\u00cdTICAS P\\u00daBLICAS DE INTEGRIDAD Y LUCHA CONTRA LA CORRUPCI\\u00d3N\",\"FUNDAMENTOS DE LAVADO DE ACTIVOS\",\"SUPERINTENDENCIA DE BANCA Y SEGUROS : ROL DE LA UNIDAD DE INTELIGENCIA FINANCIERA\",\"CONSTITUCIONALIDAD, TRATADOS Y NORMAS EN ANTICORRUPCI\\u00d3N\"]', '2026-06-19 21:03:51', '2026-06-19 21:03:51'),
(589, 49, 'Ciclo II', 'Fortalecer competencias en derecho penal, delitos conexos, criminalidad organizada y defensa del Estado, integrando investigación científica aplicada y estrategias jurídicas para enfrentar redes ilícitas con enfoque técnico, normativo y contextual.', '[\"SISTEMA PENAL ACUSATORIO Y ANTICORRUPCI\\u00d3N\",\"METODOLOG\\u00cdA DE INVESTIGACI\\u00d3N CIENT\\u00cdFICA\",\"DELITO DE LAVADO DE ACTIVOS, DELITOS CONEXOS Y EXTINCI\\u00d3N DE DOMINIO\",\"CRIMINALIDAD ORGANIZADA, LAVADO DE ACTIVOS Y CORRUPCI\\u00d3N EN LOS MERCADOS LEGALES E ILEGALES\",\"DEFENSA DEL ESTADO EN DELITOS DE LAVADOS DE ACTIVOS, CORRUPCI\\u00d3N Y EXTINCI\\u00d3N DE DOMINIO\"]', '2026-06-19 21:03:51', '2026-06-19 21:03:51'),
(590, 49, 'Ciclo III', 'Aplicar conocimientos en compliance, fraude internacional, delitos públicos y jurisprudencia penal, culminando con una investigación aplicada que articule teoría y práctica para la lucha legal y estratégica contra la corrupción y el lavado de activos.', '[\"DISE\\u00d1O Y APLICACI\\u00d3N DEL PROGRAMA DE COMPLIANCE ANTICORRUPCI\\u00d3N EN LAS BUENAS PR\\u00c1CTICAS CORPORATIVAS\",\"FRAUDE Y BLANQUEO: PERSPECTIVAS INTERNACIONALES\",\"DELITOS CONTRA LA ADMINISTRACI\\u00d3N P\\u00daBLICA\",\"AN\\u00c1LISIS DE PLENOS CASATORIOS PENALES EN ANTICORRUPCI\\u00d3N Y LAVADO DE ACTIVOS\",\"TRABAJO DE INVESTIGACI\\u00d3N APLICADA\"]', '2026-06-19 21:03:51', '2026-06-19 21:03:51'),
(591, 52, 'Ciclo I', 'Desarrollar conocimientos en gerencia de proyectos, marketing inmobiliario, planeamiento urbano, políticas de suelo, contabilidad aplicada y dirección empresarial, construyendo una base sólida para liderar procesos en el sector inmobiliario con enfoque técnico, económico y estratégico.', '[\"FUNDAMENTOS DE LA GERENCIA DE PROYECTOS\",\"DIRECCI\\u00d3N DE EMPRESAS INMOBILIARIAS\",\"CONTABILIDAD Y TRIBUTACI\\u00d3N APLICADA A LA CONSTRUCCI\\u00d3N\",\"PLANEAMIENTO URBANO Y LICENCIAS DE CONSTRUCCI\\u00d3N\",\"GERENCIA DE MARKETING INMOBILIARIO\",\"FUNDAMENTOS ECON\\u00d3MICOS DE POL\\u00cdTICAS DE SUELO\"]', '2026-06-19 21:06:47', '2026-06-19 21:06:47'),
(592, 52, 'Ciclo II', 'Fortalecer competencias en gestión de proyectos inmobiliarios, certificaciones sostenibles, valorización de activos y metodología de investigación, integrando marcos normativos, criterios económicos y ambientales para una toma de decisiones efectiva en operaciones inmobiliarias.', '[\"GESTI\\u00d3N DE PROYECTOS INMOBILIARIOS\",\"NORMATIVA Y CERTIFICACIONES PARA CONSTRUCCI\\u00d3N SOSTENIBLE\",\"VALORIZACI\\u00d3N DE ACTIVOS INMOBILIARIOS\",\"METODOLOG\\u00cdA DE LA INVESTIGACI\\u00d3N CIENT\\u00cdFICA\"]', '2026-06-19 21:06:47', '2026-06-19 21:06:47'),
(593, 52, 'Ciclo III', 'Aplicar conocimientos avanzados en derecho inmobiliario, ciudades inteligentes, gestión de portafolios, fondos de inversión y resolución de conflictos, culminando con una investigación aplicada que integre teoría, normativa y estrategia en el desarrollo urbano y del mercado inmobiliario.', '[\"DERECHO INMOBILIARIO Y CONTRATOS\",\"NEGOCIACI\\u00d3N Y GESTI\\u00d3N DE CONFLICTOS EN EL SECTOR INMOBILIARIO\",\"GESTI\\u00d3N DE PORTAFOLIOS DE BIENES RA\\u00cdCES Y FONDOS DE INVERSI\\u00d3N INMOBILIARIA\",\"TRABAJO DE INVESTIGACI\\u00d3N APLICADO\",\"VIVIENDA SOCIAL, CIUDADES INTELIGENTES Y DESARROLLO URBANO DEL FUTURO\"]', '2026-06-19 21:06:47', '2026-06-19 21:06:47'),
(594, 54, 'Ciclo I', 'Formar en los fundamentos de la gestión de proyectos BIM, modelado digital con Revit, y planificación colaborativa en etapas iniciales de diseño.', '[\"FUNDAMENTOS DE LA GERENCIA DE PROYECTOS\",\"FUNDAMENTOS Y EST\\u00c1NDARES BIM\",\"TALLER ACTUALIZACI\\u00d3N SOFTWARE MODELAMIENTO DIGITAL REVIT CONSTRUCTION\",\"PLANIFICACI\\u00d3N Y CONTROL BIM EN OBRA I\",\"GESTI\\u00d3N DEL MODELO DE INFORMACI\\u00d3N EN LA ETAPA DE DISE\\u00d1O\",\"TRABAJO COLABORATIVO, IPD, VDC E INTEROPERABILIDAD I\"]', '2026-06-19 21:10:27', '2026-06-19 21:10:27'),
(595, 54, 'Ciclo II', 'Profundizar en la gestión del modelo BIM en construcción, tecnologías emergentes y metodología de investigación aplicada.', '[\"GESTI\\u00d3N DEL MODELO DE INFORMACI\\u00d3N Y TECNOLOG\\u00cdAS EMERGENTES EN LA ETAPA DE CONSTRUCCI\\u00d3N\",\"PLANIFICACI\\u00d3N Y CONTROL BIM EN OBRA II\",\"FUNDAMENTOS PARA LA GESTI\\u00d3N DE ACTIVOS CON BIM (OPERACI\\u00d3N Y MANTENIMIENTO)\",\"METODOLOGIA DE LA INVESTIGACION CIENTIFICA\"]', '2026-06-19 21:10:27', '2026-06-19 21:10:27'),
(596, 54, 'Ciclo III', 'Desarrollar habilidades en gestión de riesgos, contratos colaborativos e implementación BIM, culminando con un trabajo de investigación aplicada.', '[\"GESTI\\u00d3N DE LA CALIDAD Y RIESGOS EN PROYECTOS DE CONSTRUCCI\\u00d3N BIM\",\"GESTI\\u00d3N DE CONTRATOS COLABORATIVOS\",\"IMPLEMENTACI\\u00d3N BIM\",\"TRABAJO DE INVESTIGACION APLICADA\",\"TRABAJO COLABORATIVO, IPD, VDC E INTEROPERABILIDAD II\"]', '2026-06-19 21:10:27', '2026-06-19 21:10:27'),
(597, 55, 'Ciclo I', 'Formar en fundamentos de gerencia de proyectos, normativa, liderazgo y planificación para la construcción sostenible.', '[\"FUNDAMENTOS DE LA GERENCIA DE PROYECTOS\",\"LIDERAZGO Y COMUNICACI\\u00d3N PARA GERENCIAR PROYECTOS\",\"PLANIFICACI\\u00d3N Y CONTROL DEL ALCANCE EN PROYECTOS DE CONSTRUCCI\\u00d3N\",\"GESTI\\u00d3N AMBIENTAL Y CONSTRUCCI\\u00d3N SOSTENIBLE\",\"RESULTADO OPERATIVO E INGENIER\\u00cdA DE COSTOS\",\"NORMATIVIDAD, LEGISLACI\\u00d3N EN LA CONSTRUCCI\\u00d3N\"]', '2026-06-19 21:14:29', '2026-06-19 21:14:29'),
(598, 55, 'Ciclo II', 'Desarrollar competencias en gestión financiera, metodologías ágiles, colaboración BIM e investigación aplicada a proyectos.', '[\"GESTI\\u00d3N FINANCIERA Y CONTRACTUAL EN LA CONSTRUCCI\\u00d3N\",\"TRABAJO COLABORATIVO BIM Y TECNOLOG\\u00cdA EN PROYECTOS DE CONSTRUCCI\\u00d3N\",\"METODOLOG\\u00cdA DE LA INVESTIGACI\\u00d3N CIENT\\u00cdFICA\",\"FILOSOF\\u00cdA LEAN CONSTRUCTION, ENFOQUES \\u00c1GILES E H\\u00cdBRIDOS\"]', '2026-06-19 21:14:29', '2026-06-19 21:14:29'),
(599, 55, 'Ciclo III', 'Especializar en gestión de calidad, PMO, certificación PMP y ejecución contractual de obras públicas.', '[\"OFICINA DE GESTI\\u00d3N DE PROYECTOS (PMO) Y MECANISMOS DE RESOLUCI\\u00d3N DE DISPUTAS\",\"PREPARACI\\u00d3N CERTIFICACI\\u00d3N INTERNACIONAL PMP\",\"EJECUCI\\u00d3N CONTRACTUAL DE OBRAS P\\u00daBLICAS Y ASOCIACIONES P\\u00daBLICO-PRIVADAS\",\"TRABAJO DE INVESTIGACI\\u00d3N APLICADA\",\"GESTI\\u00d3N DE LA CALIDAD, SEGURIDAD Y SALUD EN EL TRABAJO Y GESTI\\u00d3N DE RIESGOS\"]', '2026-06-19 21:14:29', '2026-06-19 21:14:29'),
(600, 56, 'Ciclo I', 'Formar en fundamentos del Estado, ética pública y planificación estratégica para una gestión gubernamental eficiente.', '[\"TEOR\\u00cdA DEL ESTADO Y GOBERNABILIDAD DEMOCR\\u00c1TICA\",\"ESTRUCTURA Y ORGANIZACI\\u00d3N DEL ESTADO\",\"PLANIFICACI\\u00d3N ESTRAT\\u00c9GICA EN EL ESTADO\",\"GESTI\\u00d3N DEL TALENTO HUMANO EN EL SECTOR P\\u00daBLICO\",\"\\u00c9TICA, INTEGRIDAD Y RESPONSABILIDAD SOCIAL EN LA GESTI\\u00d3N P\\u00daBLICA\"]', '2026-06-19 21:16:24', '2026-06-19 21:16:24'),
(601, 56, 'Ciclo II', 'Desarrollar competencias en finanzas públicas, gobierno electrónico e implementación de políticas con enfoque social.', '[\"GOBIERNO ELECTR\\u00d3NICO Y TECNOLOG\\u00cdAS DE LA INFORMACI\\u00d3N\",\"NEGOCIACI\\u00d3N Y SOLUCI\\u00d3N DE CONFLICTOS SOCIALES\",\"IMPLEMENTACI\\u00d3N DE POL\\u00cdTICAS P\\u00daBLICAS\",\"METODOLOG\\u00cdA DE LA INVESTIGACI\\u00d3N CIENT\\u00cdFICA\",\"SISTEMA FINANCIERO, PRESUPUESTO E INVERSIONES DEL ESTADO\"]', '2026-06-19 21:16:24', '2026-06-19 21:16:24'),
(602, 56, 'Ciclo III', 'Especializar en derecho administrativo, control estatal y modernización del Estado con investigación aplicada.', '[\"DERECHO ADMINISTRATIVO EN LA GESTI\\u00d3N P\\u00daBLICA Y DEFENSA JUR\\u00cdDICA DEL ESTADO\",\"GESTI\\u00d3N DE ADQUISICIONES Y CONTRATACIONES CON EL ESTADO\",\"SISTEMA DE CONTROL Y GESTI\\u00d3N DE RIESGOS EN EL ESTADO\",\"MODERNIZACI\\u00d3N Y DESCENTRALIZACI\\u00d3N DEL ESTADO\",\"TRABAJO DE INVESTIGACI\\u00d3N APLICADO\"]', '2026-06-19 21:16:24', '2026-06-19 21:16:24'),
(603, 57, 'Ciclo I', 'Fortalecer el conocimiento del aparato estatal, planificación estratégica, gobernabilidad y responsabilidad social en la gestión pública, desarrollando competencias organizativas, éticas y de liderazgo que permitan un desempeño eficiente en contextos públicos descentralizados y orientados al bien común.', '[\"TEOR\\u00cdA DEL ESTADO Y GOBERNABILIDAD DEMOCR\\u00c1TICA\",\"ESTRUCTURA Y ORGANIZACI\\u00d3N DEL ESTADO\",\"PLANIFICACI\\u00d3N ESTRAT\\u00c9GICA EN EL ESTADO\",\"GESTI\\u00d3N DEL TALENTO HUMANO EN EL SECTOR P\\u00daBLICO\",\"\\u00c9TICA, INTEGRIDAD Y RESPONSABILIDAD SOCIAL EN LA GESTI\\u00d3N P\\u00daBLICA\"]', '2026-06-19 21:21:00', '2026-06-19 21:21:00'),
(604, 57, 'Ciclo II', 'Desarrollar capacidades para aplicar herramientas digitales, resolver conflictos sociales, implementar políticas públicas y comprender los sistemas financieros del Estado, integrando metodologías investigativas que permitan analizar y transformar procesos públicos con enfoque técnico y participativo.', '[\"GOBIERNO ELECTR\\u00d3NICO Y TECNOLOG\\u00cdAS DE LA INFORMACI\\u00d3N\",\"NEGOCIACI\\u00d3N Y SOLUCI\\u00d3N DE CONFLICTOS SOCIALES\",\"IMPLEMENTACI\\u00d3N DE POL\\u00cdTICAS P\\u00daBLICAS\",\"METODOLOG\\u00cdA DE LA INVESTIGACI\\u00d3N CIENT\\u00cdFICA\",\"SISTEMA FINANCIERO, PRESUPUESTO E INVERSIONES DEL ESTADO\"]', '2026-06-19 21:21:00', '2026-06-19 21:21:00'),
(605, 57, 'Ciclo III', 'Consolidar competencias en derecho administrativo, contratación pública, control de riesgos, descentralización estatal y gestión aplicada, culminando con un trabajo de investigación que articula conocimientos normativos, técnicos y estratégicos en beneficio de la eficiencia y modernización estatal.', '[\"DERECHO ADMINISTRATIVO EN LA GESTI\\u00d3N P\\u00daBLICA Y LA DEFENSA JUR\\u00cdDICA DEL ESTADO\",\"GESTI\\u00d3N DE ADQUISICIONES Y CONTRATACIONES CON EL ESTADO\",\"SISTEMA DE CONTROL Y GESTI\\u00d3N DE RIESGOS EN EL ESTADO\",\"MODERNIZACI\\u00d3N Y DESCENTRALIZACI\\u00d3N DEL ESTADO\",\"TRABAJO DE INVESTIGACI\\u00d3N APLICADO\"]', '2026-06-19 21:21:00', '2026-06-19 21:21:00'),
(606, 62, 'Ciclo I', 'Desarrollar competencias en el uso de redes sociales, creación de contenidos, gamificación, habilidades digitales, marketing educativo y metodologías investigativas, orientadas al diseño y aplicación de estrategias innovadoras en contextos virtuales de aprendizaje con enfoque pedagógico y tecnológico.', '[\"LAS REDES SOCIALES EN LA EDUCACI\\u00d3N\",\"CREACI\\u00d3N DE CONTENIDOS Y GAMIFICACI\\u00d3N EN EL AULA\",\"COMPETENCIAS DIGITALES Y HABILIDADES PARA EL TRABAJO DEL FUTURO\",\"TECNOLOG\\u00cdAS DIGITALES PARA EL APRENDIZAJE Y TRABAJO COLABORATIVO\",\"GESTI\\u00d3N DE MARKETING EN INSTITUCIONES EDUCATIVAS\",\"METODOLOG\\u00cdA DE LA INVESTIGACI\\u00d3N CIENT\\u00cdFICA\"]', '2026-06-19 21:32:24', '2026-06-19 21:32:24'),
(607, 62, 'Ciclo II', 'Consolidar habilidades para gestionar entornos virtuales, aplicar neuro tecnologías, estándares de calidad, privacidad digital y formular proyectos educativos, culminando con un trabajo de investigación aplicada que articule teoría, práctica y transformación educativa en entornos digitales.', '[\"EST\\u00c1NDARES DE CALIDAD Y TECNOLOG\\u00cdAS DIGITALES\",\"COGNICI\\u00d3N Y NEUROTECNOLOG\\u00cdAS DIGITALES\",\"FORMULACI\\u00d3N DE PROYECTOS EDUCATIVOS EN ENTORNOS VIRTUALES\",\"TRABAJO DE INVESTIGACI\\u00d3N APLICADA\",\"ENTORNOS VIRTUALES DE APRENDIZAJE, E-LEARNING\",\"IDENTIDAD DIGITAL, PROTECCI\\u00d3N DE DATOS Y PRIVACIDAD EN EL ENTORNO DIGITAL\"]', '2026-06-19 21:32:24', '2026-06-19 21:32:24'),
(608, 64, 'Ciclo I', 'Desarrollar en los doctorandos una comprensión crítica y analítica del derecho desde diversas perspectivas teóricas y metodológicas, integrando enfoques sociológicos, antropológicos y metodológicos.', '[\"AN\\u00c1LISIS CR\\u00cdTICO DEL DERECHO P\\u00daBLICO Y PRIVADO: PROBLEMAS CONTEMPOR\\u00c1NEOS Y METODOLOG\\u00cdAS DE INVESTIGACI\\u00d3N JUR\\u00cdDICA\",\"BASES SOCIOL\\u00d3GICAS Y ANTROPOL\\u00d3GICAS DEL DERECHO\",\"M\\u00c9TODO DEL CASO: ESTRATEGIAS DE AN\\u00c1LISIS Y APLICACI\\u00d3N EN EL DERECHO\"]', '2026-06-19 21:35:44', '2026-06-19 21:35:44'),
(609, 64, 'Ciclo II', 'Profundizar en la ética profesional y en los desafíos contemporáneos del derecho frente a la inteligencia artificial, así como consolidar una base epistemológica para la investigación jurídica rigurosa.', '[\"\\u00c9TICA DE LA ABOGAC\\u00cdA Y DEONTOLOG\\u00cdA FORENSE\",\"EPISTEMOLOG\\u00cdA EN LA INVESTIGACI\\u00d3N JUR\\u00cdDICA\",\"DERECHO, INTELIGENCIA ARTIFICIAL Y GOBERNANZA DE INTERNET\"]', '2026-06-19 21:35:44', '2026-06-19 21:35:44'),
(610, 64, 'Ciclo III', 'Comprender los procesos globales e históricos que han influido en las estructuras jurídicas actuales, e iniciar el proceso de investigación doctoral con base epistemológica sólida.', '[\"DERECHO GLOBAL DE LAS ORGANIZACIONES INTERNACIONALES E INTEGRACI\\u00d3N ECON\\u00d3MICA\",\"PROCESO HIST\\u00d3RICO DE LAS IDEAS POL\\u00cdTICAS\",\"SEMINARIO DE TESIS I\"]', '2026-06-19 21:35:44', '2026-06-19 21:35:44'),
(611, 64, 'Ciclo IV', 'Fomentar la producción científica con estándares internacionales y fortalecer la capacidad de argumentación jurídica en el marco del respeto por los derechos humanos.', '[\"NORMAS APA Y REDACCI\\u00d3N DE UN ART\\u00cdCULO DE INVESTIGACI\\u00d3N\",\"SEMINARIO DE TESIS II\",\"DERECHOS HUMANOS, ARGUMENTACI\\u00d3N JUR\\u00cdDICA Y CONSTITUCIONALISMO\"]', '2026-06-19 21:35:44', '2026-06-19 21:35:44'),
(612, 64, 'Ciclo V', 'Desarrollar competencias en métodos alternativos de solución de conflictos y continuar con el desarrollo de la tesis doctoral.', '[\"ARBITRAJE INTERNACIONAL Y SOLUCI\\u00d3N DE CONFLICTOS\",\"EXPERIENCIA CURRICULAR ELECTIVA\",\"SEMINARIO DE TESIS III\"]', '2026-06-19 21:35:44', '2026-06-19 21:35:44'),
(613, 64, 'Ciclo VI', 'Concluir la tesis doctoral con rigor metodológico y científico, articulando los aportes del programa a la investigación jurídica original.', '[\"SEMINARIO DE TESIS IV\"]', '2026-06-19 21:35:44', '2026-06-19 21:35:44'),
(614, 67, 'Ciclo I', 'Formar en desarrollo infantil integral, recursos digitales y fundamentos pedagógicos para la educación inicial.', '[\"RECURSOS DIGITALES PARA EL APRENDIZAJE EN EDUCACI\\u00d3N INICIAL\",\"DESARROLLO DEL LENGUAJE E INICIACI\\u00d3N EN LA COMUNICACI\\u00d3N\",\"FUNDAMENTOS Y PROCESOS PEDAG\\u00d3GICOS EN EL NIVEL INICIAL\",\"METODOLOG\\u00cdA DE LA INVESTIGACI\\u00d3N CIENT\\u00cdFICA\",\"DESARROLLO INFANTIL: COGNICI\\u00d3N, AFECTIVIDAD Y PSICOMOTRICIDAD\"]', '2026-06-19 21:40:02', '2026-06-19 21:40:02'),
(615, 67, 'Ciclo II', 'Desarrollar estrategias con padres, programación curricular y evaluación de aprendizajes en educación inicial.', '[\"ESTRATEGIAS DE TRABAJO CON PADRES Y COMUNIDAD\",\"PROGRAMACI\\u00d3N CURRICULAR EN INICIAL\",\"EVALUACI\\u00d3N DE LOS APRENDIZAJES EN EDUCACI\\u00d3N INICIAL\",\"DESARROLLO DEL PENSAMIENTO L\\u00d3GICO MATEM\\u00c1TICO EN EDUCACI\\u00d3N INICIAL\",\"TRABAJO ACAD\\u00c9MICO FIN DE CURSO\"]', '2026-06-19 21:40:02', '2026-06-19 21:40:02'),
(616, 67, 'Ciclo III', NULL, '[]', '2026-06-19 21:40:02', '2026-06-19 21:40:02'),
(617, 70, 'Ciclo I', 'Desarrollar competencias en políticas educativas, gestión de recursos, talento humano y marca personal del gestor, integrando principios de ética, liderazgo y metodologías investigativas que favorezcan una administración educativa pública eficiente, responsable y centrada en la mejora continua.', '[\"POL\\u00cdTICAS EDUCATIVAS\",\"GESTI\\u00d3N DEL TALENTO HUMANO EN SECTOR P\\u00daBLCIO EDUCACI\\u00d3N\",\"MARCA PERSONAL DEL GESTOR EDUCATIVO\",\"METODOLOGIA DE LA INVESTIGACI\\u00d3N CIENT\\u00cdFICA\",\"GESTI\\u00d3N DE RECURSOS MATERIALES, ECON\\u00d3MICOS Y FINANCIEROS SECTOR P\\u00daBLICO\"]', '2026-06-19 21:46:55', '2026-06-19 21:46:55'),
(618, 70, 'Ciclo II', 'Fortalecer habilidades para evaluar, diseñar y liderar procesos educativos públicos mediante acreditación, gobierno digital, formulación de proyectos y responsabilidad administrativa, culminando con un trabajo académico que articula teoría, práctica e innovación en la gestión pública educativa.', '[\"EVALUACI\\u00d3N Y ACREDITACI\\u00d3N EDUCATIVA\",\"PROYECTOS DE DESARROLLO EDUCATIVO\",\"GOBIERNO DIGITAL EN LA GESTI\\u00d3N P\\u00daBLICA\",\"TRABAJO ACADEMICO FIN DE CURSO\",\"RESPONSABILIDAD ADMINISTRATIVA, CIVIL Y PENAL DE LA GESTI\\u00d3N P\\u00daBLICA\"]', '2026-06-19 21:46:55', '2026-06-19 21:46:55'),
(619, 73, 'Ciclo I', NULL, '[\"FUNDAMENTOS DE GERENCIA DE PROYECTOS BAJO EL ENFOQUE DEL PMI\\u00ae\",\"GOBERNANZA DE PROYECTOS Y OFICINA DE GERENCIA DE PROYECTOS\",\"CURSO DE PREPARACI\\u00d3N PARA LA CERTIFICACI\\u00d3N INTERNACIONAL PMP\\u00ae\",\"PROYECTO FINAL\",\"LIDERAZGO ESTRAT\\u00c9GICO PARA GERENCIAR PROYECTOS, PROGRAMAS Y PORTAFOLIOS\"]', '2026-06-19 21:49:21', '2026-06-19 21:49:21'),
(620, 74, 'Modulo I', NULL, '[\"Marco normativo del SINAGRED\"]', '2026-06-19 21:50:49', '2026-06-19 21:50:49'),
(621, 74, 'Modulo II', NULL, '[\"Nuevo reglamento de Inspecciones T\\u00e9cnicas de Seguridad en Edificaciones - ITSE y manual de ejecuci\\u00dbn de ITSE\"]', '2026-06-19 21:50:49', '2026-06-19 21:50:49'),
(622, 74, 'Modulo III', NULL, '[\"InspeccI\\u00f3n por riesgo\"]', '2026-06-19 21:50:49', '2026-06-19 21:50:49'),
(623, 74, 'Modulo IV', NULL, '[\"Riesgo de incendio\"]', '2026-06-19 21:50:49', '2026-06-19 21:50:49'),
(624, 74, 'Modulo V', NULL, '[\"Conceptos sobre protecci\\u00f3n pasiva\",\"aforo y dimensiones de los componentes de evacuaci\\u00f3n\"]', '2026-06-19 21:50:49', '2026-06-19 21:50:49'),
(625, 74, 'Modulo VI', NULL, '[\"Conceptos sobre protecci\\u00f3n activa y plan de seguridad\"]', '2026-06-19 21:50:49', '2026-06-19 21:50:49'),
