INSERT INTO `testimonios` (`id`, `nombre`, `profesion`, `comentario`, `calificacion`, `imagen`, `created_at`, `updated_at`) VALUES
(1, 'Marcos Quispe', 'Ing. Civil', 'Es una universidad maravillosa para estudiar. La red de Alumni es sólida, lo que ayuda a encontrar oportunidades laborales.', 5, 'testimonio_1779402856198.png', '2026-05-22 03:34:16', '2026-05-22 20:18:31'),
(2, 'Carlos Alfredo', 'Abogado', 'Muy buena universidad, gran oportunidad para estudiantes que quieran crecer profesionalmente.', 5, 'testimonio_17794631029.png', '2026-05-22 20:18:22', '2026-05-22 20:18:22'),
(3, 'Lucía Fernández', 'Psicóloga', 'La calidad académica es excelente y el acompañamiento docente marcó la diferencia en mi formación.', 4, 'testimonio_1779463144163.png', '2026-05-22 20:19:04', '2026-05-22 20:19:04'),
(4, 'Ana María Salas', 'Contadora', 'Gracias a UPRIT logré acceder a un trabajo apenas egresé. Las prácticas profesionales fueron clave.', 3, 'testimonio_1779489303198.png', '2026-05-22 20:19:34', '2026-05-23 03:35:03');
